using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    #region CreateOrder — Happy Path

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
        Assert.AreEqual(9.99m, order.Items[0].Price);
        Assert.AreEqual(2, order.Items[0].Quantity);
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
        Assert.IsTrue(order.CreatedAt > DateTime.UtcNow.AddSeconds(-5));
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_TotalIsSumOfPriceTimesQuantity()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 3 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 2 },
            new() { ProductName = "Doohickey", Price = 5.75m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        // 10*3 + 25.5*2 + 5.75*1 = 30 + 51 + 5.75 = 86.75
        Assert.AreEqual(86.75m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
        Assert.AreEqual("cust-2", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds_ForEachOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder — Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", items));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region CreateOrder — Edge Cases

    [TestMethod]
    public void CreateOrder_ItemWithZeroQuantity_TotalIsZero()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 15.00m, Quantity = 0 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(0m, order.Total);
    }

    [TestMethod]
    [DataRow(1.01, 3, 3.03, DisplayName = "1.01 × 3 = 3.03")]
    [DataRow(0.10, 7, 0.70, DisplayName = "0.10 × 7 = 0.70")]
    [DataRow(99.99, 1, 99.99, DisplayName = "99.99 × 1 = 99.99")]
    [DataRow(33.33, 3, 99.99, DisplayName = "33.33 × 3 = 99.99")]
    public void CreateOrder_DecimalPrices_PreciseTotalCalculation(
        double price, int quantity, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Precision Item", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    [TestMethod]
    public void CreateOrder_StoresOrderInternally_OrderRetrievableAfterCreation()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-1", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrderId_ReturnsTheOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 12.50m, Quantity = 2 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-1", result.CustomerId);
        Assert.AreEqual(25.00m, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreations_ReturnsCorrectOrder()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Alpha", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Beta", Price = 20.00m, Quantity = 1 }
        };
        var order1 = _sut.CreateOrder("cust-1", items1);
        var order2 = _sut.CreateOrder("cust-2", items2);

        // Act
        var result = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(order2.Id, result.Id);
        Assert.AreEqual(20.00m, result.Total);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_SingleOrder_ReturnsThatOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 8.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("cust-1", result[0].CustomerId);
        Assert.AreEqual(8.00m, result[0].Total);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 20.00m, Quantity = 2 }
        };
        _sut.CreateOrder("cust-1", items1);
        _sut.CreateOrder("cust-1", items2);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
        Assert.AreEqual(10.00m, result[0].Total);
        Assert.AreEqual(40.00m, result[1].Total);
    }

    [TestMethod]
    public void GetOrdersByCustomer_UnknownCustomer_ReturnsEmptyList()
    {
        // Act
        var result = _sut.GetOrdersByCustomer("non-existent-customer");

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_OnlyReturnsMatchingOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);
