     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
         };

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.IsNotNull(order);
         Assert.IsNotNull(order.Id);
         Assert.AreNotEqual(string.Empty, order.Id);
         Assert.AreEqual("cust-1", order.CustomerId);
         Assert.AreEqual(19.98m, order.Total);
         Assert.AreEqual(1, order.Items.Count);
         Assert.AreEqual("Widget", order.Items[0].ProductName);
         Assert.AreEqual(9.99m, order.Items[0].Price);
         Assert.AreEqual(2, order.Items[0].Quantity);
         Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
         Assert.IsTrue(order.CreatedAt > DateTime.UtcNow.AddSeconds(-5));
     }

     [TestMethod]
